#!/usr/bin/env python3
from pathlib import Path
import json

ROOT = Path.cwd()
FILES = {'.env.email.example': '# Betsy Home email notification settings\n# Local MVP can run without these; notifications will be logged only.\n\nEMAIL_FROM="Betsy Home <no-reply@your-domain.com>"\nSUPPORT_EMAIL="support@your-domain.com"\n\n# Optional future provider\n# RESEND_API_KEY=re_replace_me\n\n# In local development, keep this true so emails are printed/logged instead of sent.\nEMAIL_LOG_ONLY=true\n', 'docs/email-notifications.md': '# Betsy Home email notification system\n\nThis patch adds local-safe notification templates and logging.\n\n## Local MVP behavior\n\nNo external email provider is required.\n\nWhen a notification is triggered, it is:\n\n- printed in the Next.js terminal\n- written to `.local-notifications/notifications.jsonl`\n\n## Templates included\n\n- order confirmation\n- seller new order alert\n- shipping update\n- refund request submitted\n- refund approved\n- refund rejected\n- review reminder\n- admin manual refund follow-up\n\n## Test routes\n\nOpen:\n\n```text\nhttp://localhost:3000/admin/notifications\n```\n\nTrigger a local test notification:\n\n```text\nhttp://localhost:3000/api/notifications/test\n```\n\n## Production later\n\nBefore real launch:\n\n- Add `EMAIL_FROM`\n- Add `SUPPORT_EMAIL`\n- Add a real provider such as Resend/SMTP\n- Set `EMAIL_LOG_ONLY=false`\n- Connect notification triggers to real order/refund/review events\n', 'src/lib/notification-templates.ts': 'export type NotificationKind =\n  | "order_confirmation"\n  | "seller_new_order"\n  | "shipping_update"\n  | "refund_request_submitted"\n  | "refund_approved"\n  | "refund_rejected"\n  | "review_reminder"\n  | "admin_manual_refund_followup";\n\nexport type NotificationPayload = {\n  orderNumber?: string;\n  orderTotal?: string;\n  shopName?: string;\n  customerName?: string;\n  customerEmail?: string;\n  sellerEmail?: string;\n  productTitle?: string;\n  trackingCarrier?: string;\n  trackingNumber?: string;\n  trackingUrl?: string;\n  refundReason?: string;\n  resolutionNote?: string;\n  adminReference?: string;\n  actionUrl?: string;\n};\n\nexport type RenderedNotification = {\n  kind: NotificationKind;\n  subject: string;\n  text: string;\n  html: string;\n};\n\nfunction escapeHtml(value: string) {\n  return value\n    .replaceAll("&", "&amp;")\n    .replaceAll("<", "&lt;")\n    .replaceAll(">", "&gt;")\n    .replaceAll(\'"\', "&quot;");\n}\n\nfunction paragraph(lines: string[]) {\n  return lines.filter(Boolean).join("\\n");\n}\n\nfunction htmlPage(title: string, bodyLines: string[]) {\n  const body = bodyLines\n    .filter(Boolean)\n    .map((line) => `<p>${escapeHtml(line)}</p>`)\n    .join("");\n\n  return `<!doctype html>\n<html>\n  <body style="font-family:Arial,sans-serif;background:#fbf4ea;padding:24px;color:#2b211d;">\n    <div style="max-width:640px;margin:auto;background:#fff;border:1px solid #ead7c5;border-radius:20px;padding:28px;">\n      <p style="letter-spacing:0.25em;text-transform:uppercase;color:#b85f45;font-weight:700;">Betsy Home</p>\n      <h1 style="margin:0 0 16px;font-size:28px;">${escapeHtml(title)}</h1>\n      ${body}\n    </div>\n  </body>\n</html>`;\n}\n\nexport function renderNotificationTemplate(\n  kind: NotificationKind,\n  payload: NotificationPayload\n): RenderedNotification {\n  const orderNumber = payload.orderNumber ?? "your order";\n  const shopName = payload.shopName ?? "Betsy Home";\n  const orderTotal = payload.orderTotal ?? "";\n  const productTitle = payload.productTitle ?? "your item";\n  const actionUrl = payload.actionUrl ?? "";\n\n  switch (kind) {\n    case "order_confirmation": {\n      const subject = `Order confirmed: ${orderNumber}`;\n      const lines = [\n        `Thanks for your order from ${shopName}.`,\n        orderTotal ? `Order total: ${orderTotal}` : "",\n        actionUrl ? `View your order: ${actionUrl}` : "",\n      ];\n      return {\n        kind,\n        subject,\n        text: paragraph(lines),\n        html: htmlPage(subject, lines),\n      };\n    }\n\n    case "seller_new_order": {\n      const subject = `New order received: ${orderNumber}`;\n      const lines = [\n        `You received a new order for ${shopName}.`,\n        productTitle ? `Item: ${productTitle}` : "",\n        orderTotal ? `Order total: ${orderTotal}` : "",\n        actionUrl ? `Manage this order: ${actionUrl}` : "",\n      ];\n      return {\n        kind,\n        subject,\n        text: paragraph(lines),\n        html: htmlPage(subject, lines),\n      };\n    }\n\n    case "shipping_update": {\n      const subject = `Shipping update for ${orderNumber}`;\n      const lines = [\n        `Your order from ${shopName} has a shipping update.`,\n        payload.trackingCarrier ? `Carrier: ${payload.trackingCarrier}` : "",\n        payload.trackingNumber ? `Tracking number: ${payload.trackingNumber}` : "",\n        payload.trackingUrl ? `Track package: ${payload.trackingUrl}` : "",\n      ];\n      return {\n        kind,\n        subject,\n        text: paragraph(lines),\n        html: htmlPage(subject, lines),\n      };\n    }\n\n    case "refund_request_submitted": {\n      const subject = `Refund request submitted: ${orderNumber}`;\n      const lines = [\n        `A refund or cancellation request was submitted for ${orderNumber}.`,\n        payload.refundReason ? `Reason: ${payload.refundReason}` : "",\n        actionUrl ? `Review request: ${actionUrl}` : "",\n      ];\n      return {\n        kind,\n        subject,\n        text: paragraph(lines),\n        html: htmlPage(subject, lines),\n      };\n    }\n\n    case "refund_approved": {\n      const subject = `Refund approved: ${orderNumber}`;\n      const lines = [\n        `The refund request for ${orderNumber} was approved.`,\n        payload.resolutionNote ? `Seller note: ${payload.resolutionNote}` : "",\n      ];\n      return {\n        kind,\n        subject,\n        text: paragraph(lines),\n        html: htmlPage(subject, lines),\n      };\n    }\n\n    case "refund_rejected": {\n      const subject = `Refund update: ${orderNumber}`;\n      const lines = [\n        `The refund request for ${orderNumber} was not approved.`,\n        payload.resolutionNote ? `Seller note: ${payload.resolutionNote}` : "",\n      ];\n      return {\n        kind,\n        subject,\n        text: paragraph(lines),\n        html: htmlPage(subject, lines),\n      };\n    }\n\n    case "review_reminder": {\n      const subject = `How was your ${productTitle}?`;\n      const lines = [\n        `We hope your order from ${shopName} arrived safely.`,\n        `Leave a review when you have a moment.`,\n        actionUrl ? `Leave a review: ${actionUrl}` : "",\n      ];\n      return {\n        kind,\n        subject,\n        text: paragraph(lines),\n        html: htmlPage(subject, lines),\n      };\n    }\n\n    case "admin_manual_refund_followup": {\n      const subject = `Manual refund follow-up needed: ${orderNumber}`;\n      const lines = [\n        `A seller approved a refund, but a Stripe refund ID or manual reference still needs admin confirmation.`,\n        payload.adminReference ? `Reference: ${payload.adminReference}` : "",\n        actionUrl ? `Open admin refunds: ${actionUrl}` : "",\n      ];\n      return {\n        kind,\n        subject,\n        text: paragraph(lines),\n        html: htmlPage(subject, lines),\n      };\n    }\n\n    default: {\n      const subject = `Betsy Home notification`;\n      const lines = [`A marketplace notification is available.`];\n      return {\n        kind,\n        subject,\n        text: paragraph(lines),\n        html: htmlPage(subject, lines),\n      };\n    }\n  }\n}\n\nexport function getNotificationTemplatePreviews() {\n  const sample: NotificationPayload = {\n    orderNumber: "BH-20260606-GQL59-1",\n    orderTotal: "$29.00",\n    shopName: "Betsy Clay Atelier",\n    productTitle: "Handmade Sage Green Ceramic Candle Holder",\n    trackingCarrier: "DHL",\n    trackingNumber: "JD014600006123456789",\n    trackingUrl: "https://example.com/track",\n    refundReason: "Found the same item cheaper on another seller.",\n    resolutionNote: "Refund approved by seller.",\n    adminReference: "manual-refund-test-001",\n    actionUrl: "http://localhost:3000/account/orders",\n  };\n\n  const kinds: NotificationKind[] = [\n    "order_confirmation",\n    "seller_new_order",\n    "shipping_update",\n    "refund_request_submitted",\n    "refund_approved",\n    "refund_rejected",\n    "review_reminder",\n    "admin_manual_refund_followup",\n  ];\n\n  return kinds.map((kind) => renderNotificationTemplate(kind, sample));\n}\n', 'src/lib/notification-service.ts': 'import fs from "fs/promises";\nimport path from "path";\nimport {\n  NotificationKind,\n  NotificationPayload,\n  renderNotificationTemplate,\n} from "@/lib/notification-templates";\n\nexport type SendNotificationInput = {\n  kind: NotificationKind;\n  to: string;\n  payload: NotificationPayload;\n  cc?: string;\n  bcc?: string;\n};\n\nfunction shouldLogOnly() {\n  return process.env.EMAIL_LOG_ONLY !== "false" || !process.env.RESEND_API_KEY;\n}\n\nasync function writeLocalNotification(entry: unknown) {\n  const dir = path.join(process.cwd(), ".local-notifications");\n  await fs.mkdir(dir, { recursive: true });\n  await fs.appendFile(\n    path.join(dir, "notifications.jsonl"),\n    `${JSON.stringify(entry)}\\n`,\n    "utf-8"\n  );\n}\n\nexport async function sendNotification(input: SendNotificationInput) {\n  const rendered = renderNotificationTemplate(input.kind, input.payload);\n\n  const entry = {\n    createdAt: new Date().toISOString(),\n    mode: shouldLogOnly() ? "log_only" : "provider_ready",\n    to: input.to,\n    cc: input.cc,\n    bcc: input.bcc,\n    subject: rendered.subject,\n    kind: input.kind,\n    text: rendered.text,\n  };\n\n  console.log("[notification]", entry);\n  await writeLocalNotification(entry);\n\n  // Local MVP intentionally logs only. Provider integration can be enabled later\n  // without changing templates or event trigger points.\n  return {\n    ok: true,\n    loggedOnly: shouldLogOnly(),\n    subject: rendered.subject,\n  };\n}\n\nexport async function sendOrderConfirmation(to: string, payload: NotificationPayload) {\n  return sendNotification({ kind: "order_confirmation", to, payload });\n}\n\nexport async function sendSellerNewOrderAlert(to: string, payload: NotificationPayload) {\n  return sendNotification({ kind: "seller_new_order", to, payload });\n}\n\nexport async function sendShippingUpdate(to: string, payload: NotificationPayload) {\n  return sendNotification({ kind: "shipping_update", to, payload });\n}\n\nexport async function sendRefundRequestSubmitted(to: string, payload: NotificationPayload) {\n  return sendNotification({ kind: "refund_request_submitted", to, payload });\n}\n\nexport async function sendRefundApproved(to: string, payload: NotificationPayload) {\n  return sendNotification({ kind: "refund_approved", to, payload });\n}\n\nexport async function sendRefundRejected(to: string, payload: NotificationPayload) {\n  return sendNotification({ kind: "refund_rejected", to, payload });\n}\n\nexport async function sendReviewReminder(to: string, payload: NotificationPayload) {\n  return sendNotification({ kind: "review_reminder", to, payload });\n}\n\nexport async function sendAdminManualRefundFollowup(\n  to: string,\n  payload: NotificationPayload\n) {\n  return sendNotification({ kind: "admin_manual_refund_followup", to, payload });\n}\n', 'src/app/api/notifications/test/route.ts': 'import { NextResponse } from "next/server";\nimport { sendNotification } from "@/lib/notification-service";\n\nexport const dynamic = "force-dynamic";\n\nexport async function GET() {\n  const result = await sendNotification({\n    kind: "order_confirmation",\n    to: "customer@betsyhome.test",\n    payload: {\n      orderNumber: "BH-20260606-GQL59-1",\n      orderTotal: "$29.00",\n      shopName: "Betsy Clay Atelier",\n      productTitle: "Handmade Sage Green Ceramic Candle Holder",\n      actionUrl: "http://localhost:3000/account/orders",\n    },\n  });\n\n  return NextResponse.json({\n    ok: true,\n    message:\n      "Test notification logged. Check the Next.js terminal and .local-notifications/notifications.jsonl.",\n    result,\n  });\n}\n', 'src/app/(admin)/admin/notifications/page.tsx': 'import { getNotificationTemplatePreviews } from "@/lib/notification-templates";\n\nexport const dynamic = "force-dynamic";\n\nexport default function AdminNotificationsPage() {\n  const previews = getNotificationTemplatePreviews();\n\n  return (\n    <main className="mx-auto max-w-6xl px-6 py-12">\n      <div className="flex flex-wrap items-start justify-between gap-4">\n        <div>\n          <p className="text-sm font-bold uppercase tracking-[0.35em] text-clay">\n            Admin\n          </p>\n          <h1 className="mt-4 text-4xl font-black text-charcoal">\n            Email notifications\n          </h1>\n          <p className="mt-2 max-w-3xl text-charcoal/70">\n            Local-safe notification templates for order, shipping, refund, review,\n            and admin follow-up workflows. During MVP testing, notifications are\n            logged instead of sent.\n          </p>\n        </div>\n\n        <a\n          href="/api/notifications/test"\n          className="rounded-full bg-clay px-6 py-3 text-sm font-black text-white"\n        >\n          Send test notification\n        </a>\n      </div>\n\n      <section className="mt-8 grid gap-4 md:grid-cols-3">\n        <div className="rounded-3xl border border-clay/20 bg-white p-6">\n          <p className="text-sm text-charcoal/60">Mode</p>\n          <p className="mt-3 text-3xl font-black text-charcoal">\n            {process.env.EMAIL_LOG_ONLY === "false" ? "Provider" : "Log only"}\n          </p>\n        </div>\n\n        <div className="rounded-3xl border border-clay/20 bg-white p-6">\n          <p className="text-sm text-charcoal/60">Templates</p>\n          <p className="mt-3 text-3xl font-black text-charcoal">{previews.length}</p>\n        </div>\n\n        <div className="rounded-3xl border border-clay/20 bg-white p-6">\n          <p className="text-sm text-charcoal/60">Local log</p>\n          <p className="mt-3 text-lg font-black text-charcoal">\n            .local-notifications\n          </p>\n        </div>\n      </section>\n\n      <section className="mt-6 grid gap-4">\n        {previews.map((preview) => (\n          <article\n            key={preview.kind}\n            className="rounded-3xl border border-clay/20 bg-white p-6"\n          >\n            <div className="flex flex-wrap items-center justify-between gap-3">\n              <div>\n                <p className="text-sm font-bold uppercase tracking-[0.25em] text-clay">\n                  {preview.kind.replaceAll("_", " ")}\n                </p>\n                <h2 className="mt-2 text-2xl font-black text-charcoal">\n                  {preview.subject}\n                </h2>\n              </div>\n              <span className="rounded-full bg-cream px-4 py-2 text-xs font-black text-charcoal/70">\n                Template\n              </span>\n            </div>\n\n            <pre className="mt-4 whitespace-pre-wrap rounded-2xl bg-cream p-4 text-sm text-charcoal/80">\n              {preview.text}\n            </pre>\n          </article>\n        ))}\n      </section>\n    </main>\n  );\n}\n'}

def ensure_parent(path: Path):
    path.parent.mkdir(parents=True, exist_ok=True)

def write_file(path_str: str, content: str):
    path = ROOT / path_str
    ensure_parent(path)
    path.write_text(content, encoding="utf-8")
    print(f"wrote {path_str}")

for path_str, content in FILES.items():
    write_file(path_str, content)

pkg_path = ROOT / "package.json"
if pkg_path.exists():
    try:
        pkg = json.loads(pkg_path.read_text(encoding="utf-8"))
        scripts = pkg.setdefault("scripts", {})
        scripts.setdefault("notifications:test", "node -e \"fetch('http://localhost:3000/api/notifications/test').then(r=>r.text()).then(console.log)\"")
        pkg_path.write_text(json.dumps(pkg, indent=2) + "\n", encoding="utf-8")
        print("updated package.json with notifications:test script")
    except Exception as error:
        print("package.json update skipped:", error)

print("\nDone.")
print("Next:")
print("  rm -rf .next")
print("  npx prisma generate")
print("  npm run dev")
print("Then open:")
print("  http://localhost:3000/admin/notifications")
print("  http://localhost:3000/api/notifications/test")
